// Audio processing configuration
#define LEQ_PERIOD        1
#define MIC_OFFSET_DB     3.0103
#define MIC_SENSITIVITY   -26
#define MIC_REF_DB        94.0
#define MIC_OVERLOAD_DB   116.0
#define MIC_NOISE_DB      29
#define MIC_BITS          24

#define SAMPLE_RATE       48000
#define SAMPLE_BITS       32
