bool isValidPm(float val) { return val > 0.0f && val < 1000.0f; }
bool isValidHumidity(float val) { return val > 0.0f && val < 100.0f; }
bool isValidTemperature(float val) { return val > -40.0f && val < 70.0f; }
bool isValidVoc(float val) { return val >= 0.0f; }
bool isValidNox(float val) { return val >= 0.0f; }
bool isValidCo2(uint16_t val) { return val > 0 && val < 40000; }

